module RefModule (
    input clk,
    input sreset,
    input load_enable,
    input shift,
    input [23:0] data,
    output [23:0] q );reg [23:0] obf_q_reg;

always @(posedge clk) begin
    if (sreset)
        obf_q_reg <= 24'b0;
    else if (load_enable)
        obf_q_reg <= data;
    else if (shift)
        obf_q_reg <= {obf_q_reg[22:0], 1'b0};
end

assign q = obf_q_reg;

endmodule
